def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0.0
        residual = capacity - item
        for step in range(1, 6):
            if residual <= 0:
                score += 15 * (1 / step)
            else:
                exp_component = np.exp(-residual / (step * item + 1))
                if step % 2 == 0:
                    score += (1 / residual) * exp_component * step
                else:
                    score -= residual * exp_component / step
            residual *= 0.7
        if capacity < item:
            score += np.sin(item) * 5
        elif capacity > item * 5:
            score -= np.log1p(capacity) * 0.8
        if 0.5 < ratio < 0.75:
            score *= 1.25
        elif 0.25 < ratio <= 0.5:
            score *= 0.85
        for power in range(2, 5):
            score += (ratio ** power) * ((-1) ** power) * np.sqrt(capacity + 1) / power
        if score > 50:
            score = 50 + np.tanh(score - 50) * 10
        elif score < -20:
            score = -20 + np.tanh(score + 20) * 5
        priorities[i] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        max_finite = np.max(priorities[finite_mask])
        priorities[~finite_mask] = max_finite + 20
    else:
        priorities[:] = 100
    return priorities
